PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "seaql_migrations" ( "version" varchar NOT NULL PRIMARY KEY, "applied_at" integer NOT NULL );

CREATE TABLE IF NOT EXISTS "sync_queue" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "table_name" varchar NOT NULL, "record_identifier" varchar NOT NULL, "operation" varchar NOT NULL, "created_at" varchar NOT NULL );


CREATE TABLE IF NOT EXISTS "note_categories" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "label" varchar NOT NULL, "description" text NULL );
CREATE TABLE IF NOT EXISTS "workspaces" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "name" varchar NOT NULL, "description" varchar NOT NULL, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL , is_default BOOLEAN NOT NULL DEFAULT FALSE, is_hidden BOOLEAN NOT NULL DEFAULT FALSE, is_secured BOOLEAN NOT NULL DEFAULT FALSE, password_hash TEXT);
CREATE TABLE IF NOT EXISTS "snippets" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "title" varchar NULL, "language" varchar NULL, "code" text NOT NULL, "description" text NULL, "is_pinned" boolean NOT NULL DEFAULT FALSE, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL, "workspace_identifier" uuid_text, FOREIGN KEY ("workspace_identifier") REFERENCES "workspaces" ("identifier") ON DELETE CASCADE );
CREATE TABLE IF NOT EXISTS "todo" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "title" varchar NOT NULL, "description" text NULL, "due_date" date_text NULL, "priority" enum_text NOT NULL DEFAULT 'medium', "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL, "workspace_identifier" uuid_text, "done" boolean NOT NULL DEFAULT FALSE, FOREIGN KEY ("workspace_identifier") REFERENCES "workspaces" ("identifier") ON DELETE CASCADE );
CREATE TABLE IF NOT EXISTS "bookmark" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "title" varchar NOT NULL, "url" varchar NOT NULL, "tag" enum_text NOT NULL DEFAULT 'development', "workspace_identifier" uuid_text, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL, FOREIGN KEY ("workspace_identifier") REFERENCES "workspaces" ("identifier") ON DELETE CASCADE );
CREATE TABLE IF NOT EXISTS "reminder" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "title" varchar NOT NULL, "description" text NULL, "recurring" boolean NOT NULL DEFAULT FALSE, "recurrence_rule" varchar NULL, "alarm_sound" varchar NULL, "workspace_identifier" uuid_text, "remind_at" timestamp_with_timezone_text NOT NULL, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL, FOREIGN KEY ("workspace_identifier") REFERENCES "workspaces" ("identifier") ON DELETE CASCADE );
CREATE TABLE IF NOT EXISTS "recycle_bin" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "item_id" uuid_text NOT NULL, "item_type" enum_text NOT NULL, "workspace_identifier" uuid_text, "payload" text NOT NULL, "deleted_at" timestamp_with_timezone_text NOT NULL, FOREIGN KEY ("workspace_identifier") REFERENCES "workspaces" ("identifier") ON DELETE CASCADE );
CREATE TABLE IF NOT EXISTS "notes" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "title" varchar NOT NULL, "content" text NOT NULL, "categories" json_text NULL, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL, "workspace_identifier" uuid_text, FOREIGN KEY ("workspace_identifier") REFERENCES "workspaces" ("identifier") ON DELETE CASCADE );
CREATE TABLE IF NOT EXISTS "user_preference" ( "identifier" uuid_text NOT NULL PRIMARY KEY, "first_name" varchar NOT NULL, "last_name" varchar NOT NULL, "email" varchar NOT NULL, "workspace_identifier" uuid_text, "created_at" timestamp_with_timezone_text NOT NULL, "updated_at" timestamp_with_timezone_text NOT NULL, FOREIGN KEY ("workspace_identifier") REFERENCES "workspaces" ("identifier") ON DELETE CASCADE );
CREATE TRIGGER bookmark_sync_insert
AFTER INSERT ON bookmark
BEGIN
VALUES (randomblob(16), 'bookmark', lower(hex(NEW.identifier)), 'INSERT', datetime('now'));
END;
CREATE TRIGGER bookmark_sync_update
AFTER UPDATE ON bookmark
BEGIN
VALUES (randomblob(16), 'bookmark', lower(hex(NEW.identifier)), 'UPDATE', datetime('now'));
END;
CREATE TRIGGER bookmark_sync_delete
AFTER DELETE ON bookmark
BEGIN
VALUES (randomblob(16), 'bookmark', lower(hex(OLD.identifier)), 'DELETE', datetime('now'));
END;
CREATE TRIGGER notes_sync_insert
AFTER INSERT ON notes
BEGIN
VALUES (randomblob(16), 'notes', lower(hex(NEW.identifier)), 'INSERT', datetime('now'));
END;
CREATE TRIGGER notes_sync_update
