END;
CREATE TRIGGER reminder_sync_update
AFTER UPDATE ON reminder
BEGIN
VALUES (randomblob(16), 'reminder', lower(hex(NEW.identifier)), 'UPDATE', datetime('now'));
END;
CREATE TRIGGER reminder_sync_delete
AFTER DELETE ON reminder
BEGIN
