INSERT INTO snippets VALUES(X'2e4a2bac17cb4743a542258c1e8a2631','Tauri workflow to push on release','YAML',replace('name: publish\n\non:\n  push:\n    tags:\n      - "v*"\n\njobs:\n  publish-tauri:\n    permissions:\n      contents: write\n\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - platform: macos-latest\n            args: "--target aarch64-apple-darwin"\n\n          - platform: macos-latest\n            args: "--target x86_64-apple-darwin"\n\n          - platform: ubuntu-22.04\n            args: ""\n\n          - platform: windows-latest\n            args: ""\n\n    runs-on: ${{ matrix.platform }}\n\n    steps:\n      - uses: actions/checkout@v4\n\n      # Linux dependencies\n      - name: install dependencies (ubuntu only)\n        if: matrix.platform == ''ubuntu-22.04''\n        run: |\n          sudo apt-get update\n          sudo apt-get install -y \\n            libwebkit2gtk-4.1-dev \\n            libappindicator3-dev \\n            librsvg2-dev \\n            patchelf \\n            libasound2-dev \\n            xdg-utils\n\n      # Node setup\n      - name: setup node\n        uses: actions/setup-node@v4\n        with:\n          node-version: 20\n          cache: npm\n          cache-dependency-path: almonds/package-lock.json\n\n      # Rust toolchain\n      - name: install Rust\n        uses: dtolnay/rust-toolchain@stable\n        with:\n          targets: ${{ matrix.platform == ''macos-latest'' && ''aarch64-apple-darwin,x86_64-apple-darwin'' || '''' }}\n\n      # Rust cache\n      - name: Rust cache\n        uses: swatinem/rust-cache@v2\n        with:\n          workspaces: "./almonds/src-tauri -> target"\n\n      # Install frontend dependencies\n      - name: install frontend dependencies\n        run: npm ci\n        working-directory: almonds\n\n      # Build + Release\n      - uses: tauri-apps/tauri-action@v0\n        env:\n          GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}\n        with:\n          projectPath: almonds\n          tagName: v__VERSION__\n          releaseName: "App v__VERSION__"\n          releaseBody: "Download the latest version here."\n          releaseDraft: false\n          prerelease: false\n          args: ${{ matrix.args }}','\n',char(10)),'Build tauri desktop app',0,'2026-03-02T12:08:05.200153+01:00','2026-03-04T11:56:36.299545+00:00',X'eade09869f2a43bfba57c60c5a5c5e7c');
INSERT INTO snippets VALUES(X'9727301991cd4fe6a146db482d1ae89e','Release tauri app','Bash',replace('#!/usr/bin/env bash\nset -e\n\nTAURI_CONFIG="almonds/src-tauri/tauri.conf.json"\n\nBUMP_TYPE=${1:-patch}\n\nif ! command -v jq &> /dev/null; then\n  echo "jq is required but not installed."\n  exit 1\nfi\n\n# Read current version\nCURRENT_VERSION=$(jq -r ''.version'' "$TAURI_CONFIG")\n\nIFS=''.'' read -r MAJOR MINOR PATCH <<< "$CURRENT_VERSION"\n\ncase "$BUMP_TYPE" in\n  major)\n    MAJOR=$((MAJOR + 1))\n    MINOR=0\n    PATCH=0\n    ;;\n  minor)\n    MINOR=$((MINOR + 1))\n    PATCH=0\n    ;;\n  patch)\n    PATCH=$((PATCH + 1))\n    ;;\n  *)\n    echo "Invalid bump type: $BUMP_TYPE"\n    echo "Use: patch | minor | major"\n    exit 1\n    ;;\nesac\n\nNEW_VERSION="$MAJOR.$MINOR.$PATCH"\nTAG="v$NEW_VERSION"\n\necho "Current version: $CURRENT_VERSION"\necho "New version: $NEW_VERSION"\n\n# Update tauri.conf.json\ntmp=$(mktemp)\njq ".version = \"$NEW_VERSION\"" "$TAURI_CONFIG" > "$tmp"\nmv "$tmp" "$TAURI_CONFIG"\n\necho "Updated Tauri version."\n\n# Commit\ngit add "$TAURI_CONFIG"\ngit commit -m "release: v$NEW_VERSION"\n\n# Tag\ngit tag "$TAG"\n\n# Push\n# git push origin release\ngit push origin "$TAG"\n\necho "Release $TAG created 🚀"','\n',char(10)),NULL,0,'2026-03-02T12:09:09.942621+01:00','2026-03-02T12:09:09.942819+01:00',X'eade09869f2a43bfba57c60c5a5c5e7c');
INSERT INTO snippets VALUES(X'2c0028cc6a3043c2a0de5febf78a3a53','go conflict','Go',replace('\n	inviterName, err := utils.ExtractInviterInformation(\n		ctx,\n		providerIdentifier,\n		accountType,\n	)\n	if err != nil {\n		return response.ClientInvitationResponse{}, err\n	}','\n',char(10)),NULL,0,'2026-03-18T08:08:27.149914+01:00','2026-03-18T08:08:27.150028+01:00',X'eade09869f2a43bfba57c60c5a5c5e7c');
INSERT INTO snippets VALUES(X'48b4d64018514c0aa9babd4d35d1d160','format personal message','HTML',replace('{{ if .Tx.Data.note }}\n<div class="success-box" style="margin-top: 24px;">\n  <p style="margin:0;">\n    <strong>A personal note from {{ .Tx.Data.inviter_name }}:</strong>\n  </p>\n  <p style="margin-top: 8px; margin-bottom:0; white-space: pre-line;">\n    {{ .Tx.Data.note  }}\n  </p>\n</div>\n{{ end }}','\n',char(10)),NULL,0,'2026-03-24T22:50:34.510148+01:00','2026-03-24T22:50:34.510483+01:00',X'e4a9def41a4247609e8eb54c76d82a3d');
