INSERT INTO snippets VALUES(X'5e07f2d44690412fbeb8bdfa96115c4e','Sor data by date or null','SQL',replace('SELECT * \nFROM provider_clients \nWHERE client_identifier = ?\nORDER BY \n  booking_last_completed_at IS NULL,\n  booking_last_completed_at DESC,\n  created_at DESC','\n',char(10)),NULL,0,'2026-04-14T13:55:59.916261+01:00','2026-04-14T13:55:59.916489+01:00',X'e4a9def41a4247609e8eb54c76d82a3d');
