INSERT INTO snippets VALUES(X'dba0820720a84004add17fc6ed47aa70','SQL Story','SQL',replace('select status from booking where raw_identifier = ''01KGHWK3BRC3S3GNDJG6HSVDBD’;\n\nUpdate status from booking where raw_identifier = ''01KGHWK3BRC3S3GNDJG6HSVDBD’;\n\n\n\nSELECT \n    u.email,\n    EXISTS (\n        SELECT 1\n        FROM user_2fa_config c\n        WHERE c.user_identifier = u.identifier\n    ) AS 2fa_exists\nFROM user u\nWHERE u.email = ''noon@gmail.com'';','\n',char(10)),NULL,0,'2026-04-24T11:44:29.704052+01:00','2026-04-28T10:53:20.264147+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
