INSERT INTO recycle_bin VALUES(X'1fc77c76de254516b9146dad929999e6',X'9a2c1adea33142019ee815be523e745d','note',X'ed42af204199419299e0965e2263d49e','{"identifier":"9a2c1ade-a331-4201-9ee8-15be523e745d","title":"Road to Snr Rust","content":"So I’m curating a guide to relearn Rust, I’m giving it a year to learn and learn it well to become very skilled in it, build zero deps app, and more things of that sort. \n\n&nbsp;\n\nI’ll be curating my journey here ","categories":[],"createdAt":"2026-03-05T07:33:08.880858Z","updatedAt":"2026-03-05T07:33:08.880858Z","workspaceIdentifier":"ed42af20-4199-4192-99e0-965e2263d49e"}','2026-03-05T07:33:13.284781+00:00');
