INSERT INTO recycle_bin VALUES(X'bd54571afa164ecfa0eee7a1a1bf9469',X'be544aaf255f4585bebb2ee0b8bf7d33','note',X'e4a9def41a4247609e8eb54c76d82a3d','{"identifier":"be544aaf-255f-4585-bebb-2ee0b8bf7d33","title":"Working on TOTP workflow","content":"- Use the totp-rs crate [https://crates.io/crates/totp-rs](https://crates.io/crates/totp-rs)\n- see articles here [https://levelup.gitconnected.com/rust-axum-totp-based-two-factor-authentication-2fa-server-bb5829f6c3a3](https://levelup.gitconnected.com/rust-axum-totp-based-two-factor-authentication-2fa-server-bb5829f6c3a3)\n- Sample implementation here github.com/0Itsuki0/Rust_TOTP2FAServer\n\n&nbsp;\n\n## Notes\n\n1. Send the OTP as data between the server and client \n2. The FE should be able to stream the QR code for this a. session may be needed\n\n&nbsp;","categories":[],"createdAt":"2026-03-09T06:42:05.939574Z","updatedAt":"2026-03-09T06:42:05.939574Z","workspaceIdentifier":"e4a9def4-1a42-4760-9e8e-b54c76d82a3d"}','2026-03-09T06:42:10.523956+00:00');
INSERT INTO recycle_bin VALUES(X'9fa08fb36e5149d3805eecc42462e9bd',X'82dd39cca0d84c3db1894f588fd3682d','note',X'eade09869f2a43bfba57c60c5a5c5e7c','{"identifier":"82dd39cc-a0d8-4c3d-b189-4f588fd3682d","title":"2FA setup flow.","content":"1. the user send their password + the 2fa strategy \n2. A code is sent and it against their setup — for this, the token table needs to be updated, and an event is dispatched here \n3. in the event + email they extract token and confirm\n4. when confirmed, the record is updated. \n\n&nbsp;","categories":[],"createdAt":"2026-02-26T10:57:08.930852Z","updatedAt":"2026-02-26T10:57:08.930852Z","workspaceIdentifier":"eade0986-9f2a-43bf-ba57-c60c5a5c5e7c"}','2026-03-20T20:21:43.281716+00:00');
