INSERT INTO notes VALUES(X'24d500d978ff4506831aada51c5a1622','Working on TOTP workflow',replace('- Use the totp-rs crate [https://crates.io/crates/totp-rs](https://crates.io/crates/totp-rs)\n- see articles here [https://levelup.gitconnected.com/rust-axum-totp-based-two-factor-authentication-2fa-server-bb5829f6c3a3](https://levelup.gitconnected.com/rust-axum-totp-based-two-factor-authentication-2fa-server-bb5829f6c3a3)\n- Sample implementation here github.com/0Itsuki0/Rust_TOTP2FAServer\n\n&nbsp;\n\n## Notes\n\n1. Send the OTP as data between the server and client \n2. The FE should be able to stream the QR code for this a. session may be needed\n\n&nbsp;','\n',char(10)),'[]','2026-03-09T06:42:05.921169+00:00','2026-03-09T06:42:05.921170+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
