INSERT INTO notes VALUES(X'b49ea5fcd3c44461a653a084613936c3','Shurbs',replace('Nice UI already—clean, modern, and structured. Turning this into a mobile app is mostly about **prioritization + compression**, not redesigning everything.\n\nHere’s how I’d translate it :point_down:\n\n---\n\n## :android: Mobile Layout Concept\n\n### 1. **Bottom Navigation (instead of sidebar)**\n\nReplace the left sidebar with a 4–5 tab bottom nav:\n\n- :house: Home\n- :memo: Notes\n- :bookmark: Bookmarks\n- :alarm_clock: Reminders\n- :gear: More (settings, moodboard, etc.)\n\n:point_right: This keeps primary actions reachable with the thumb.\n\n---\n\n### 2. **Top Section (Condensed Header)**\n\nCurrent:\n\n> “Good evening, Redwood” + stats\n\nMobile version:\n\n- Keep greeting (shorter)\n- Show **1–2 key stats only**\n\nExample:\n\n```\nGood evening 👋\n1 active task today\n\n```\n\nOptional: swipeable stat chips (Notes / Bookmarks / Todos)\n\n---\n\n### 3. **Quick Actions → Floating Action Button (FAB)**\n\nRight panel becomes:\n\n- **FAB (+)** bottom right\n\nOn tap → opens sheet:\n\n- New note\n- Add bookmark\n- New todo\n- New snippet\n\n:point_right: Much more native mobile UX than side panel buttons.\n\n---\n\n### 4. **Cards Stack (Main Content)**\n\nTurn dashboard into vertical scroll:\n\n#### :small_blue_diamond: Active Todos (Top priority)\n\n- Show 1–3 items max\n- Progress bar stays\n- Tap → full list\n\n#### :small_blue_diamond: Recent Notes\n\n- Show 2 items\n- Swipe → more\n\n#### :small_blue_diamond: Bookmarks\n\n- Horizontal scroll cards (important change)\n- Much better for mobile\n\n---\n\n### 5. **Reminders (Inline, not empty box)**\n\nInstead of:\n\n> “No upcoming reminders”\n\nUse:\n\n- Collapsible section OR\n- Hide when empty\n\n:point_right: Empty states waste too much mobile space.\n\n---\n\n### 6. **Search (Move or Hide)**\n\nTop search bar → either:\n\n- Icon in header → opens full screen search  \nOR\n- Dedicated tab\n\n---\n\n## :fire: Key UX Improvements (Important)\n\n- Reduce **visual density** → mobile needs breathing room\n- Increase **tap targets** (cards, buttons)\n- Use **horizontal scroll for collections** (bookmarks especially)\n- Prioritize **“what needs attention” first** (todos always on top)\n\n---\n\n## :bulb: If you want it to feel premium\n\n- Add subtle **card elevation / blur**\n- Use **gesture navigation** (swipe between sections)\n- Animate FAB → action sheet smoothly\n- Micro-interactions (checkbox tick, bookmark save)\n\n---\n\n## :brain: One honest critique\n\nRight now your UI is **desktop-first thinking**:\n\n- Too many panels\n- Too much equal weight\n\nMobile needs:\n\n> **Hierarchy, not completeness**\n\n---\n\n&nbsp;','\n',char(10)),'[]','2026-04-03T19:21:05.200819+00:00','2026-04-03T19:21:05.200819+00:00',X'8acc2c420fda43ae8636c9f39067e51d');
INSERT INTO notes VALUES(X'7008df62bc8c43f199144be59c61d582','Almonds mobile','**Google Calendar:** The connect button is wired up and shows connected state. The actual OAuth flow is stubbed with clear `TODO` comments in [calendar_controller.dart:115-135](vscode-webview://0lqp41ahh3u5m932u0cfi3ll4rqhcqi7if0jbqmu12g9ct5i0e9m/shurbs/lib/src/controllers/calendar_controller.dart#L115-L135) — you''ll need to add OAuth credentials in Google Cloud Console + add the reversed client ID to iOS `Info.plist` and Android `build.gradle`, then uncomment the `google_sign_in` call.','[]','2026-04-07T00:47:47.685453+00:00','2026-04-07T00:47:47.685454+00:00',X'8acc2c420fda43ae8636c9f39067e51d');
