INSERT INTO notes VALUES(X'e8739123bab049289b51edcee53d391f','CDS talk:',replace('### Outline.\n\n- CV, types the how and content, see Google XYZ format \n  - See ref here [https://www.wonsulting.com/job-search-hub/the-power-of-quantifiable-results-how-to-use-the-xyz-formula-to-supercharge-your-resume](https://www.wonsulting.com/job-search-hub/the-power-of-quantifiable-results-how-to-use-the-xyz-formula-to-supercharge-your-resume)\n  - [https://ecs.ihu.edu.gr/co/employment-cvcletter/types-cv.html](https://ecs.ihu.edu.gr/co/employment-cvcletter/types-cv.html)\n- Cover letter, the why, the content, the brag, and the importance \n- Safety online, talk about Phishing, warm, Rats virus\n- Talk about PDF and Image highjacking. \n  - [https://blog.checkpoint.com/research/the-weaponization-of-pdfs-68-of-cyberattacks-begin-in-your-inbox-with-22-of-these-hiding-in-pdfs/](https://blog.checkpoint.com/research/the-weaponization-of-pdfs-68-of-cyberattacks-begin-in-your-inbox-with-22-of-these-hiding-in-pdfs/)\n- Safety in job applications \n- Raffle draw \n- Free and mod app highjacking. \n- Spamming and email mask. \n- managing email and revovery\n- typo-squating\n\n&nbsp;','\n',char(10)),'["test"]','2026-04-16T09:24:27.900017+00:00','2026-04-17T10:04:55.128463+00:00',X'ed42af204199419299e0965e2263d49e');
