INSERT INTO notes VALUES(X'f37a36542da74215811e91f7328a7f2b','Interview guide',replace('Here’s a curated list of **sample interview questions** for the **Senior Rust Engineer** role at Stivlon Consulting (or their client). I’ve grouped them to match the job description: core Rust concepts, backend/systems focus, architecture & optimization, leadership/experience, and behavioral/soft skills.\n\nInterviewers for senior roles usually mix these with:\n\n- Questions about your past projects (especially production Rust systems).\n- A take-home coding task or live coding (e.g., building a small async service, fixing ownership issues, or designing a microservice).\n- System design discussion (e.g., “Design a high-throughput backend service in Rust”).\n\n### 1. Core Rust Concepts (They will test these deeply — 3+ years production experience means they expect strong answers)\n\n- Explain Rust’s **ownership model**. How does it prevent common bugs like data races or use-after-free errors? Give a simple example.\n- What is **borrowing** in Rust? Explain the rules for mutable vs immutable borrows and why you can’t have multiple mutable references at the same time.\n- What are **lifetimes**? When do you need to annotate them explicitly? Explain with an example involving function parameters or struct fields.\n- What is the difference between `String` and `&str`? When would you use each, and how does this relate to ownership?\n- Explain the difference between `Box<T>`, `Rc<T>`, and `Arc<T>`. When would you choose one over the others?\n- How does Rust handle error handling? Compare `Result<T, E>` and `Option<T>`. When do you use `?` operator vs explicit matching?\n- What is the `Drop` trait? Give an example where implementing it is useful.\n- Explain `Copy` vs `Clone`. Which types implement `Copy` by default, and why?\n\n### 2. Concurrency & Asynchronous Programming (Job mentions high-performance, concurrency, and Tokio/async-await)\n\n- How does Rust ensure **thread safety** without a garbage collector? Talk about `Send` and `Sync` traits.\n- Explain how you would use `std::thread` vs **Tokio** for concurrent work. What are the trade-offs?\n- Describe a real-world scenario where you used `async/await` with Tokio. How did you handle backpressure, cancellation, or spawning tasks?\n- What are channels in Rust `mpsc`, `broadcast`, etc.)? When would you use them in a backend service?\n- How do you share data across async tasks or threads safely? (e.g., `Arc<Mutex<T>>`, `RwLock`, or lock-free alternatives)\n\n### 3. Backend Development & Systems (REST APIs, databases, microservices, production systems)\n\n- How would you design and implement a scalable **RESTful backend service** in Rust? What crates would you use (e.g., Axum, Actix-Web, Warp)?\n- Describe your experience integrating **databases** in Rust (PostgreSQL with SQLx or Diesel, Redis, MongoDB). How do you handle connection pooling and async queries?\n- How do you structure a Rust project for a **microservices** architecture? Talk about modules, crates, error handling across services, and API contracts.\n- What strategies do you use for **API integration** (REST, gRPC, third-party services) while keeping code clean and testable?\n- How would you make a Rust backend service **fault-tolerant** and resilient (e.g., retries, circuit breakers, graceful shutdown)?\n\n### 4. Performance, Optimization & Architecture\n\n- How do you optimize **memory usage** and **performance** in Rust? Give examples related to zero-copy, avoiding allocations, or using the right data structures.\n- Explain how you would handle **high concurrency** and low-latency requirements in a production system.\n- What tools or techniques do you use for **profiling** and debugging performance issues in Rust (e.g., cargo flamegraph, perf, heaptrack)?\n- Describe a time you architected a **scalable, secure system** in Rust. What trade-offs did you make?\n- How do you ensure your Rust code is **well-tested**? (unit tests, integration tests, property-based testing with proptest, etc.)\n\n### 5. Leadership, Mentoring & Best Practices (Senior-level expectations)\n\n- How do you conduct **code reviews**? What do you look for in Rust code specifically (idiomatic Rust, safety, performance)?\n- Describe your experience **mentoring junior engineers** on Rust concepts like ownership or async.\n- How do you stay up-to-date with the Rust ecosystem (new crates, language features, best practices)?\n- Tell us about a complex technical issue you troubleshot and resolved in a production Rust system.\n- How do you collaborate with frontend, DevOps, and product teams when building end-to-end features?\n\n### 6. Nice-to-Have / Bonus Topics (Blockchain, FinTech, Containers, Cloud)\n\n- Do you have experience with **blockchain/Web3** or **FinTech** systems in Rust? (e.g., using rust-bitcoin, solana crates, or building secure payment backends)\n- How have you used **Docker** and **Kubernetes** with Rust services?\n- Describe your experience with **CI/CD pipelines** for Rust projects.\n- Have you worked with cloud platforms (AWS, GCP, Azure) for deploying Rust applications? What services did you use?\n- What experience do you have with other systems languages like C/C++ or Go, and how does it compare to Rust?\n\n### 7. Behavioral / Soft Skills & Experience Questions\n\n- Tell us about your most challenging Rust project. What made it difficult, and how did you overcome it?\n- How do you approach **problem-solving** when debugging a complex concurrency or memory issue?\n- Describe a time you took ownership of a large feature or architectural decision.\n- Why are you interested in this Senior Rust Engineer role? What attracts you to working in Abuja (or remotely with occasional office visits)?\n- Where do you see yourself in 5 years? (Some interviews ask this.)\n\n### Preparation Tips Specific to This Role\n\n- Review the Rust Book chapters on Ownership, Borrowing, Lifetimes, Concurrency, and Async (especially Tokio tutorial).\n- Be ready to discuss **real production experience** — they emphasize “high-performance, secure, and scalable systems” and “production environments.”\n- Practice explaining concepts clearly (they value communication and mentoring).\n- Expect questions on Linux CLI, Git workflows, and basic system design.\n- If they mention their client’s domain (FinTech, blockchain, or high-performance backend), prepare relevant examples.\n\nWould you like me to expand any section with **model answers**, suggest a **coding exercise** to practice, or focus on a particular area (e.g., async/Tokio or system design)? Just let me know your experience level or which topics you want to drill deeper on! Good luck with the application — ₦1M monthly is solid for the role.\n\n&nbsp;\n\n### Q/A \n\n1. &nbsp;\n\n&nbsp;','\n',char(10)),'[]','2026-04-17T12:57:54.866675+00:00','2026-04-17T16:43:25.388921+00:00',X'ed42af204199419299e0965e2263d49e');
INSERT INTO notes VALUES(X'34196ba1ef2d47558d530e4d3220100d','Design inspirations',replace('[https://dribbble.com/shots/23781952-Edutech-Dashboard-Design](https://dribbble.com/shots/23781952-Edutech-Dashboard-Design)  \n  \ndashboard.   \n  \nUse nuxt, \n\nmake it more content ful for myself learning too ','\n',char(10)),'["figma"]','2026-04-17T13:04:49.026424+00:00','2026-04-17T13:13:02.650270+00:00',X'16426bcfb43d41b48b27204386db3d1e');
INSERT INTO notes VALUES(X'315f4a710cec49dc8beb6d6a1511570c','New content',replace('[https://tranqbay.slack.com/archives/C060UFFM8SJ/p1775813408759969?thread_ts=1775035680.783159&cid=C060UFFM8SJ](https://tranqbay.slack.com/archives/C060UFFM8SJ/p1775813408759969?thread_ts=1775035680.783159&cid=C060UFFM8SJ)  \nSubject\n\nWelcome! Your account with [Therapist Name] is ready\n\nBody\n\nHello [Client Name],\n\nWelcome! Your account has been successfully created so you can connect with [Therapist Name].\n\nYou were invited to join their private practice space on the platform, where you can securely manage your sessions and communication.\n\nYour Account is Ready\n\nYou can now:\n\n• Book sessions with [Therapist Name]\n\n• Send and receive messages securely\n\n• Join online therapy sessions when scheduled\n\n• Manage upcoming appointments\n\nEverything related to your therapy with [Therapist Name] will happen right here.\n\nHow It Works\n\nBook a Session – Choose a time that works for you from your therapist’s available schedule\n\nGet Reminders – You''ll receive reminders before your session\n\nJoin Your Session – If your session is online, you''ll get a secure video link inside your account\n\nStay Connected – Use messaging if you need to reach your therapist between sessions\n\nCTA Button\n\nGo to Your Dashboard(redirects them to their dashboard—the account they just created where they see only the therapist) \n\nClosing\n\nIf you have any questions, feel free to reach out to your therapist directly through the platform.\n\nWe’re glad you’re here and wish you the best on your journey.\n\nWarmly,\n\nThe Tranqbay Team. ','\n',char(10)),'[]','2026-04-21T11:57:22.732126+00:00','2026-04-21T11:57:22.732127+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'78fe570964e54805934b096b5d845d7d','Path to Systems-level programming',replace('<p><strong>Becoming a systems software engineer</strong>—the kind who builds foundational tools like Docker, container runtimes, kernels, hypervisors, or low-level infrastructure—is an awesome goal. People like Solomon Hykes (Docker''s creator) didn''t follow a rigid academic path; he was a self-taught coder from age 7, ran servers as a teenager in France, studied practical CS at Epitech, and turned deep Linux knowledge into dotCloud (which pivoted into Docker in 2013). The common thread for creators of Docker, Kubernetes-inspired tech, or modern runtimes (e.g., Firecracker at AWS) is <strong>hands-on mastery of how computers actually work under the hood</strong>—not just writing apps, but controlling processes, memory, filesystems, and hardware isolation.</p><p>In 2026, this field is hotter than ever: Rust is now production-ready in the Linux kernel (no longer "experimental"), containers and eBPF dominate cloud-native infra, and companies like Google, AWS, Red Hat, and Docker/Mirantis pay top dollar for people who can build safe, performant system software.</p><p>Here''s a practical, no-fluff roadmap to get you there. You can start today, whether you''re in school, self-taught, or switching careers.</p><h3 class="notes_heading">1. Build unbreakable foundations (3–6 months)</h3><p>Focus on what separates systems engineers from app developers:</p><ul class="note_list_unordered"><li><p><strong>Computer architecture &amp; low-level systems</strong>: Understand memory, CPUs, assembly, and how code talks to hardware.</p></li><li><p><strong>Languages</strong>: Master C (or C++) first—it''s the lingua franca of kernels and runtimes. Then add Rust (huge in 2026 for memory-safe systems code) and Go (Docker itself was written in Go).</p></li><li><p><strong>Core concepts</strong>: Processes, threads, syscalls, memory management, scheduling, filesystems, networking.</p></li></ul><p><strong>Top resources</strong>:</p><ul class="note_list_unordered"><li><p><em>Computer Systems: A Programmer''s Perspective</em> (CSAPP) by Bryant &amp; Hallaron → the #1 book for this. Do the labs.</p></li><li><p><em>Modern Operating Systems</em> by Andrew Tanenbaum.</p></li><li><p>The Rust Book (free online) + <em>Rust in Action</em> by Tim McNamara (project-based systems programming in Rust—perfect for containers/kernels).</p></li></ul><p>Practice daily: Write small C/Rust programs that use syscalls <code>strace</code> everything).</p><h3 class="notes_heading">2. Master Linux internals &amp; containerization (6–12 months)</h3><p>Docker''s magic comes from Linux primitives: namespaces (isolation), cgroups (resource limits), seccomp (security), capabilities, and filesystems (pivot_root/chroot). You need to understand these deeply.</p><p><strong>Key topics</strong>:</p><ul class="note_list_unordered"><li><p>Linux kernel basics (syscalls, modules, debugging with perf/gdb/strace).</p></li><li><p>Containers/virtualization from first principles.</p></li><li><p>Modern extensions: eBPF, Rust in kernel, rootless containers.</p></li></ul><p><strong>Best resources</strong>:</p><ul class="note_list_unordered"><li><p><em>The Linux Programming Interface</em> by Michael Kerrisk (the bible for Linux system calls).</p></li><li><p><em>Linux Kernel Development</em> by Robert Love (or current kernel docs).</p></li><li><p>Free: OSDev wiki + Linux Journey / Kernel Newbies.</p></li></ul><p><strong>Hands-on project that changes everything</strong>: Build your own mini-Docker/container runtime from scratch. There are excellent 2025–2026 tutorials for this:</p><ul class="note_list_unordered"><li><p>Use Linux tools <code>unshare</code>, <code>mount</code>, <code>pivot_root</code>) or code it in Go/Rust.</p></li><li><p>Example projects: "Build a Docker-like tool in Go" or "Minimal rootless container in Rust" (search for recent talks like the Seattle Rust User Group one).</p></li></ul><p>This single project will teach you more than most courses and looks incredible on a résumé or GitHub.</p><h3 class="notes_heading">3. Level up with projects, open source &amp; specialization (ongoing)</h3><p>Creators ship real tools. You should too.</p><ul class="note_list_unordered"><li><p>Build: A toy OS (Nand2Tetris or OSDev), a simple kernel module, or an eBPF tool.</p></li><li><p>Contribute: Start small on Linux kernel (Rust drivers are welcoming now), Podman, containerd, or Rust-for-Linux projects. Docker is mature, but the ecosystem (runc, BuildKit, etc.) always needs help.</p></li><li><p>Advanced: Study distributed systems if you want Kubernetes-scale impact, or hypervisors (QEMU/KVM).</p></li></ul><p><strong>2026 hot skills</strong>:</p><ul class="note_list_unordered"><li><p>Rust for safe systems (Linux kernel, new runtimes).</p></li><li><p>Container orchestration internals.</p></li><li><p>Performance &amp; observability (perf, bpftrace).</p></li></ul><h3 class="notes_heading">4. Education &amp; credentials (flexible)</h3><ul class="note_list_unordered"><li><p><strong>Degree</strong>: A CS bachelor''s helps (especially for big-tech interviews), but it''s not required. Hykes succeeded without one from a fancy school. Self-taught + strong GitHub &gt; degree in many cases.</p></li><li><p><strong>Certifications</strong>: Nice-to-have but secondary (e.g., CKAD/CKA for Kubernetes, but focus on building instead).</p></li><li><p><strong>Courses</strong> (if you like structure):</p><ul class="note_list_unordered"><li><p>MIT 6.828 (Operating Systems) or Berkeley CS courses (free on YouTube).</p></li><li><p>Rust for Linux materials (<a href="http://rust-for-linux.com">rust-for-linux.com</a>).</p></li></ul></li></ul><h3 class="notes_heading">5. Get the job</h3><ul class="note_list_unordered"><li><p><strong>Entry points</strong>: Start as a backend/devops engineer at a cloud-native company, then move into platform/infra teams. Internships at Red Hat, AWS, Google, or Docker-adjacent firms are gold.</p></li><li><p><strong>Portfolio</strong>: GitHub with your mini-container, kernel contributions, or performance tools. Blog about what you built (e.g., "I reimplemented namespaces in Rust").</p></li><li><p><strong>Job titles to target</strong>: Systems Software Engineer, Kernel Engineer, Container Runtime Engineer, Platform Engineer (low-level), Rust Systems Engineer.</p></li><li><p>Salaries are excellent once you''re in (especially with Rust/kernel experience).</p></li></ul><h3 class="notes_heading">Mindset &amp; timeline tips</h3><ul class="note_list_unordered"><li><p><strong>Daily habit</strong>: Read kernel source or man pages for one syscall a day. Debug real problems with <code>straceperf</code>.</p></li><li><p><strong>Communities</strong>: r/linux, r/rust, r/kernel, Linux Kernel Mailing List (<a href="http://lwn.net">lwn.net</a> for summaries), Rust for Linux Discord.</p></li><li><p>Realistic timeline: 12–24 months of focused work to land your first systems role if you already code; longer if starting from zero. Consistency beats intensity.</p></li><li><p>Challenges: Low-level debugging is brutal at first. Embrace it—that frustration is exactly what made Docker possible.</p></li></ul><p>Start <strong>today</strong> with the CSAPP book or the Rust Book + a simple container project. In a year you''ll be building the next Docker-level tools instead of just using them.</p><p>You''ve got this. The world needs more people who understand the plumbing. Drop your current background or what you''ve already built, and I can refine this plan even more. :rocket:<br><br><br><br></p><p></p><h3 class="notes_heading">Goal: Systems Engineer — Rust, C/C++, Linux<br><br><br></h3><h3 class="notes_heading">Month/stage 0ne — Learning C</h3><p>I chose the K&amp; R Programming Text — I’ll be working on exercies over the next couple of weeks <br><br>Nice direction. If you’re aiming at <strong>compilers + Linux + systems</strong>, don’t do random CRUD projects. Build things that force you to touch <strong>memory, files, processes, parsing, ABI, ELF, terminals, syscalls</strong>.</p><p style="text-align: start;">Computer Systems: A Programmer''s Perspective is a strong next read.</p><p style="text-align: start;">Project ladder:</p><h2 class="notes_heading" style="text-align: start;">Stage 1 — K&amp;R + early C (now)</h2><h3 class="notes_heading" style="text-align: start;">1. Mini <code>cat</code></h3><pre><code class="language-bash">mycat file.txt\n</code></pre><p style="text-align: start;">Learn:</p><ul class="note_list_unordered"><li><p><code>open</code></p></li><li><p><code>read</code></p></li><li><p><code>write</code></p></li><li><p>file descriptors</p></li><li><p>buffers</p></li></ul><hr><h3 class="notes_heading" style="text-align: start;">2. <code>wc</code> clone</h3><pre><code class="language-bash">mywc file.txt\n</code></pre><p style="text-align: start;">Count:</p><ul class="note_list_unordered"><li><p>lines</p></li><li><p>chars</p></li><li><p>words</p></li></ul><p style="text-align: start;">Learn:</p><ul class="note_list_unordered"><li><p>streaming</p></li><li><p>state machines</p></li></ul><hr><h3 class="notes_heading" style="text-align: start;">3. Hex viewer (<code>hexdump</code>)</h3><pre><code class="language-bash">myhex file.bin\n</code></pre><p style="text-align: start;">Output:</p><pre><code class="language-txt">48 65 6C 6C 6F\n</code></pre><p style="text-align: start;">Learn:</p><ul class="note_list_unordered"><li><p>binary I/O</p></li><li><p>formatting</p></li><li><p>memory representation</p></li></ul><hr><h2 class="notes_heading" style="text-align: start;">Stage 2 — Linux internals</h2><h3 class="notes_heading" style="text-align: start;">4. Build a shell</h3><pre><code class="language-bash">myshell\n&gt; ls\n&gt; pwd\n</code></pre><p style="text-align: start;">Need:</p><pre><code class="language-c">fork();\nexecvp();\nwait();\npipe();\n</code></pre><p style="text-align: start;">Add later:</p><ul class="note_list_unordered"><li><p>pipes</p></li><li><p>redirection</p></li><li><p>background jobs</p></li></ul><p style="text-align: start;">This project alone teaches a lot.</p><hr><h3 class="notes_heading" style="text-align: start;">5. Process monitor</h3><p style="text-align: start;">Like simplified <code>top</code>.</p><p style="text-align: start;">Read:</p><pre><code class="language-txt">/proc\n/proc/PID/status\n/proc/meminfo\n</code></pre><p style="text-align: start;">Learn:</p><ul class="note_list_unordered"><li><p>Linux process model</p></li><li><p>virtual memory</p></li><li><p>procfs</p></li></ul><hr><h3 class="notes_heading" style="text-align: start;">6. Tiny allocator</h3><p style="text-align: start;">Implement:</p><pre><code class="language-c">void* my_malloc(size_t n);\nvoid my_free(void *p);\n</code></pre><p style="text-align: start;">Start with linked list allocator.</p><p style="text-align: start;">Then:</p><ul class="note_list_unordered"><li><p>arenas</p></li><li><p>fragmentation</p></li><li><p>coalescing</p></li></ul><hr><h2 class="notes_heading" style="text-align: start;">Stage 3 — Compiler path</h2><h3 class="notes_heading" style="text-align: start;">7. Lexer</h3><p style="text-align: start;">Input:</p><pre><code class="language-txt">x = 2 + y;\n</code></pre><p style="text-align: start;">Output:</p><pre><code class="language-txt">IDENT(x)\nEQ\nNUMBER(2)\nPLUS\nIDENT(y)\nSEMICOLON\n</code></pre><hr><h3 class="notes_heading" style="text-align: start;">8. Parser</h3><p style="text-align: start;">Build AST:</p><pre><code class="language-txt">+\n / \\n2   y\n</code></pre><p style="text-align: start;">Recursive descent is fine.</p><hr><h3 class="notes_heading" style="text-align: start;">9. Tiny language</h3><p style="text-align: start;">Example:</p><pre><code class="language-txt">let x = 5;\nprint(x + 2);\n</code></pre><p style="text-align: start;">Stages:</p><pre><code class="language-txt">source\n→ lexer\n→ parser\n→ AST\n→ interpreter\n</code></pre><p style="text-align: start;">Later add codegen.</p><hr><h3 class="notes_heading" style="text-align: start;">10. Stack VM</h3><p style="text-align: start;">Instructions:</p><pre><code class="language-txt">PUSH 5\nPUSH 3\nADD\nPRINT\n</code></pre><p style="text-align: start;">Then interpreter:</p><pre><code class="language-c">switch(opcode)\n</code></pre><hr><h2 class="notes_heading" style="text-align: start;">Stage 4 — Hardcore systems</h2><h3 class="notes_heading" style="text-align: start;">11. ELF parser</h3><p style="text-align: start;">Read executable headers:</p><pre><code class="language-bash">myreadelf a.out\n</code></pre><p style="text-align: start;">Parse:</p><ul class="note_list_unordered"><li><p>ELF header</p></li><li><p>sections</p></li><li><p>symbols</p></li></ul><p style="text-align: start;">You’ll touch binaries directly.</p><hr><h3 class="notes_heading" style="text-align: start;">12. Mini linker</h3><p style="text-align: start;">Resolve symbols:</p><pre><code class="language-txt">foo.o + bar.o\n</code></pre><p style="text-align: start;">Understand relocation.</p><hr><h3 class="notes_heading" style="text-align: start;">13. Toy OS kernel</h3><p style="text-align: start;">Minimal:</p><ul class="note_list_unordered"><li><p>boot</p></li><li><p>VGA output</p></li><li><p>keyboard</p></li></ul><p style="text-align: start;">Later:</p><ul class="note_list_unordered"><li><p>paging</p></li><li><p>scheduler</p></li></ul><hr><h3 class="notes_heading" style="text-align: start;">14. <code>strace</code> clone</h3><p style="text-align: start;">Trace syscalls:</p><pre><code class="language-bash">mytrace ./app\n</code></pre><p style="text-align: start;">Use:</p><pre><code class="language-c">ptrace()\n</code></pre><hr><h3 class="notes_heading" style="text-align: start;">15. Tiny debugger</h3><p style="text-align: start;">Commands:</p><pre><code class="language-txt">break\nstep\ncontinue\n</code></pre><p style="text-align: start;">Uses:</p><ul class="note_list_unordered"><li><p><code>ptrace</code></p></li><li><p>registers</p></li><li><p>breakpoints</p></li></ul><hr><p style="text-align: start;">If I were mapping <strong>your exact path</strong>:</p><p style="text-align: start;"><strong>Now</strong><br>K&amp;R → CSAPP</p><p style="text-align: start;"><strong>Build simultaneously</strong><br><code>wc</code> → shell → lexer → parser → VM → ELF parser → debugger</p><p style="text-align: start;">That sequence basically walks toward compiler + Linux engineering.</p><p></p><h3 class="notes_heading">Time lines </h3><p>If your target is <strong>compilers + Linux + low-level systems</strong>, I’d map it like this:</p><pre><code class="language-txt">C\n↓\nCSAPP\n↓\nLinux programming\n↓\nCompiler construction\n↓\nOS / advanced systems\n</code></pre><p style="text-align: start;">More concretely:</p><h2 class="notes_heading" style="text-align: start;">1. C + projects <em>(now)</em></h2><p style="text-align: start;">Finish K&amp;R.</p><p style="text-align: start;">Build:</p><ul class="note_list_unordered"><li><p><code>wc</code></p></li><li><p><code>cat</code></p></li><li><p>shell</p></li><li><p>hex viewer</p></li><li><p>tokenizer</p></li></ul><p style="text-align: start;">Goal: stop fighting syntax and pointers.</p><p style="text-align: start;">Book: The C Programming Language</p><hr><h2 class="notes_heading" style="text-align: start;">2. CSAPP</h2><p style="text-align: start;">Book: Computer Systems: A Programmer''s Perspective</p><p style="text-align: start;">Focus on:</p><ul class="note_list_unordered"><li><p>memory</p></li><li><p>machine code</p></li><li><p>assembly</p></li><li><p>linking</p></li><li><p>virtual memory</p></li><li><p>cache</p></li><li><p>processes</p></li></ul><p style="text-align: start;">Projects:</p><ul class="note_list_unordered"><li><p>ELF parser</p></li><li><p>allocator</p></li><li><p>binary inspector</p></li></ul><hr><h2 class="notes_heading" style="text-align: start;">3. Linux programming</h2><p style="text-align: start;">Read:</p><ul class="note_list_unordered"><li><p>Advanced Programming in the UNIX Environment</p></li><li><p>The Linux Programming Interface</p></li></ul><p style="text-align: start;">Learn:</p><pre><code class="language-c">fork()\nexec()\nwait()\npipe()\nsignal()\nmmap()\npthread\nsocket\nepoll\n</code></pre><p style="text-align: start;">Projects:</p><ul class="note_list_unordered"><li><p>shell with pipes</p></li><li><p><code>strace</code> clone</p></li><li><p>mini debugger</p></li><li><p>process monitor</p></li><li><p>HTTP server</p></li></ul><hr><h2 class="notes_heading" style="text-align: start;">4. Compilers</h2><p style="text-align: start;">Books:</p><ul class="note_list_unordered"><li><p>Crafting Interpreters</p></li><li><p>Engineering a Compiler</p></li><li><p>Modern Compiler Implementation in C</p></li></ul><p style="text-align: start;">Build:</p><pre><code class="language-txt">lexer\n↓\nparser\n↓\nAST\n↓\ninterpreter\n↓\nbytecode VM\n↓\ncodegen\n</code></pre><p style="text-align: start;">Projects:</p><ul class="note_list_unordered"><li><p>toy language</p></li><li><p>VM</p></li><li><p>register allocator</p></li><li><p>optimizer</p></li></ul><hr><h2 class="notes_heading" style="text-align: start;">5. OS internals / advanced systems</h2><p style="text-align: start;">Books:</p><ul class="note_list_unordered"><li><p>Operating Systems: Three Easy Pieces</p></li><li><p>The Linux Programming Interface</p></li></ul><p style="text-align: start;">Projects:</p><ul class="note_list_unordered"><li><p>scheduler simulator</p></li><li><p>toy kernel</p></li><li><p>memory manager</p></li><li><p>filesystem</p></li><li><p>thread library</p></li></ul><hr><h2 class="notes_heading" style="text-align: start;">Optional later</h2><p style="text-align: start;"><strong>C++ (for LLVM ecosystem)</strong></p><p style="text-align: start;">Then:</p><ul class="note_list_unordered"><li><p>LLVM</p></li><li><p>Clang</p></li></ul><hr><p style="text-align: start;">A 12–18 month path could look like:</p><pre><code class="language-txt">2026:\nK&amp;R\nCSAPP\nLinux projects\n\nLate 2026:\nCompiler projects\nVM\nDebugger\n\n2027:\nLLVM\nOS internals\nKernel work\n</code></pre><p style="text-align: start;">You already have Rust background, which helps a lot once you reach compilers and systems tooling.</p><p></p>','\n',char(10)),'["rust","c++"]','2026-04-21T23:54:11.452619+00:00','2026-05-20T19:19:19.230968+00:00',X'ed42af204199419299e0965e2263d49e');
INSERT INTO notes VALUES(X'c451c15d9e024c5bb46105a1fe4b46f6','When can I rechedule?',replace('<h3><strong>Provider no show</strong></h3><pre><code>if allow_reschedule_completed_booking\n    &amp;&amp; !matches!(\n        booking.attendance_status,\n        AttendanceStatus::AutoPartial\n            | AttendanceStatus::AutoNone\n            | AttendanceStatus::ClientDisputed,\n    )\n{\n    return Err(BookingError::RescheduleBlocked);\n}\n</code></pre><p>When the booking is completed</p><p>or att stats is any of the above.''</p><p>or override from support</p><p></p><pre><code class="language-rust">let age = 54</code></pre><p></p><p><span data-name="grinning_face" data-type="emoji" class="emoji">😀</span></p><p>&nbsp;</p>','\n',char(10)),'[]','2026-04-23T11:07:15.740936+00:00','2026-04-26T12:53:20.861197+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'4465369899174b1182205ea9c5321653','Job application tracker','<table><tbody><tr><th data-colwidth="42"><p>no</p></th><th data-colwidth="278"><p>Company</p></th><th data-colwidth="160"><p>Status</p></th><th data-colwidth="158"><p>Stage</p></th></tr><tr><td data-colwidth="42"><p>1</p></td><td data-colwidth="278"><h3 style="text-align: start;">SuperPlane</h3></td><td data-colwidth="160"><p>awaiting reply</p></td><td data-colwidth="158"><p>initial/cv</p></td></tr><tr><td data-colwidth="42"><p>2</p></td><td data-colwidth="278"><p>Urban Legend</p></td><td data-colwidth="160"><p>awaiting reply</p></td><td data-colwidth="158"><p>Initial/cv</p></td></tr><tr><td data-colwidth="42"><p>3</p></td><td data-colwidth="278"><p>Philo</p></td><td data-colwidth="160"><p>awaiting reply</p></td><td data-colwidth="158"><p>Initilal/cv</p></td></tr><tr><td data-colwidth="42"><p>4</p></td><td data-colwidth="278"><p>Davidson</p></td><td data-colwidth="160"><p>Awaiting reply </p></td><td data-colwidth="158"><p>initial </p></td></tr><tr><td data-colwidth="42"><p></p></td><td data-colwidth="278"><p></p></td><td data-colwidth="160"><p></p></td><td data-colwidth="158"><p></p></td></tr><tr><td data-colwidth="42"><p></p></td><td data-colwidth="278"><p></p></td><td data-colwidth="160"><p></p></td><td data-colwidth="158"><p></p></td></tr></tbody></table><p></p>','["job","rust","backend","vue"]','2026-04-27T06:39:52.195399+00:00','2026-04-27T08:42:06.104169+00:00',X'ed42af204199419299e0965e2263d49e');
