INSERT INTO notes VALUES(X'16edd9d6eef34a58adfffa536cbd0329','Brags','<p></p><details><summary>What''s the most impactful thing you''ve built and shipped in the last two years?</summary><div data-details-content=""><p><a href="https://github.com/opeolluwa/almonds">https://github.com/opeolluwa/almonds</a><br><br>In the last five months, I built and shipped Almonds, a developer productivity app that consolidates daily workflow tools—todos, reminders, bookmarks, and screen time tracking—into a single system.</p><p>The goal was to reduce context switching by providing developers with a single place to manage execution and focus, rather than relying on multiple disconnected tools.</p><p>I handled the project end-to-end, from system design to implementation, with a strong focus on performance and simplicity using Rust.</p><p>The project was also featured by the Rust Nigeria community, which helped validate its relevance to developers.</p></div></details><details><summary>LinkedIn Profile</summary><div data-details-content=""><p><a href="https://www.linkedin.com/in/adefemi-adeoye/">https://www.linkedin.com/in/adefemi-adeoye/</a></p></div></details><p></p>','["jobs"]','2026-04-27T07:58:27.390784+00:00','2026-04-27T08:00:17.016314+00:00',X'ed42af204199419299e0965e2263d49e');
