INSERT INTO notes VALUES(X'0d1113ca069941cab48bcba83f912f0f','Page title no show —',replace('<p><br>Suppress the initial rendering of the page title </p><pre><code class="language-vue">    &lt;template #page_title&gt;\n      &lt;UButton\n        variant="ghost"\n        @click="router.back()"\n        color="neutral"\n        icon="heroicons:arrow-long-left"\n      &gt;&lt;/UButton&gt;\n    &lt;/template&gt;\n\n    &lt;template #main_content&gt;</code></pre><p></p>','\n',char(10)),'["almonds"]','2026-04-27T09:29:32.382532+00:00','2026-04-27T09:29:32.382533+00:00',X'16426bcfb43d41b48b27204386db3d1e');
INSERT INTO notes VALUES(X'5094148e5fa04122bf2a9ecf4e18cc34','Checks for 2FA',replace('<p></p><h3 class="notes_heading">Todo</h3><ol class="note_list_ordered"><li><p>If the user has a pin_code -created</p></li><li><p>if user has a pin code enabled</p></li></ol><p>booking confirmed</p><p>booking reminder</p><p>The email should have join on Android for client on tranqbay platform</p><p></p><pre><code class="language-sql">update booking set support_reschedule_override = 1 where raw_identifier = ''01KQ7D981ZCVBNZESMATPRA2ZX; \n\nupdate booking set support_reschedule_override = 0, appointment_end_time = now() where raw_identifier = ''01KQ7D981ZCVBNZESMATPRA2ZX'' ;\n </code></pre><p></p>','\n',char(10)),'[]','2026-04-27T12:33:26.660413+00:00','2026-04-28T21:14:52.593287+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'ba09e91a1f81403cb30f2a0834d6ea4a','Application Tracker','<p></p><p>Brag</p><ol><li><p>RustConf2026 <a href="https://rustfoundation.org/media/announcing-the-rustconf-2026-program-committee/">https://rustfoundation.org/media/announcing-the-rustconf-2026-program-committee/</a></p></li><li><p>TwiR <a href="https://rust-lang.org/governance/people/opeolluwa/">https://rust-lang.org/governance/people/opeolluwa/</a></p></li></ol><p></p>','[]','2026-04-28T16:55:07.370084+00:00','2026-04-28T17:03:04.223719+00:00',X'ed42af204199419299e0965e2263d49e');
INSERT INTO notes VALUES(X'b4977c2331334f28867b4475caa35b25','impl local notification','<ol class="note_list_ordered"><li><p>create local_notification table</p></li><li><p>save syn </p></li></ol><p></p>','[]','2026-05-04T11:55:58.099045+00:00','2026-05-04T11:55:58.099046+00:00',X'8acc2c420fda43ae8636c9f39067e51d');
INSERT INTO notes VALUES(X'6ae74c61b1a9475db5fa1a1df565f86d','Build error',replace('<pre><code class="language-sh">\nRun actions/setup-go@v2\nSetup go stable version spec 1.21.2\nAttempting to download 1.21.2...\nmatching 1.21.2...\nNot found in manifest.  Falling back to download directly from Go\nInstall from dist\nAcquiring go1.21.2 from https://storage.googleapis.com/golang/go1.21.2.linux-arm64.tar.gz\nError: Failed to download version 1.21.2: Error: Unexpected HTTP response: 403\n</code></pre><p></p>','\n',char(10)),'[]','2026-05-05T13:16:52.511270+00:00','2026-05-05T13:16:52.511271+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'0b2cc63129b2497698988e929c609a8c','Meeting. notes','<p></p><p></p><p></p><ul class="note_list_unordered"><li><p>Subscription model for provider —&nbsp;some features will be paid, eg AI transcription</p></li><li><p>All these are hooked inside roles —&nbsp;roles are a wrapper for permission</p></li><li><p>Each service has a way of checking the permission</p></li><li><p>A plugin will be created to inject/resolve the user’s permission.</p></li></ul><p></p><p></p><h2 class="notes_heading">User service —</h2><ol class="note_list_ordered"><li><p>a migration to include allow_push _notification </p></li><li><p>add endpoint to toggle this </p></li><li><p>all done in the user service </p></li><li><p>Confirm that the booking service exposes this </p></li></ol><p></p>','[]','2026-05-05T15:11:30.947477+00:00','2026-05-05T15:54:43.449335+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'74e5bd96006c4daeb498a3fb1da4b08d','Push notification fixes',replace('<p></p><p></p><h2 class="notes_heading">Side note:</h2><ul class="note_list_unordered"><li><p>Read-only DB replica*</p></li><li><p></p></li></ul><p></p><h2 class="notes_heading">Fixes</h2><pre><code>CREATE TABLE allowed_push_notification (\n    `identifier` BINARY (16) NOT NULL PRIMARY KEY,\n    `user_identifier` BINARY (16) NOT NULL UNIQUE,\n    `messages` TINYINT (1) NOT NULL DEFAULT 1,\n    `app_updates` TINYINT (1) NOT NULL DEFAULT 1,\n    `session_reminders` TINYINT (1) NOT NULL DEFAULT 1,\n    `booking_updates` TINYINT (1) NOT NULL DEFAULT 1,\n    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    CONSTRAINT fk_allowed_push_notification_user FOREIGN KEY (user_identifier) REFERENCES user (identifier) ON DELETE CASCADE\n);</code></pre><pre><code>CREATE TABLE users (</code></pre><pre><code>    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),</code></pre><pre><code>    name VARCHAR(100)</code></pre><pre><code>);</code></pre><p></p><ol class="note_list_ordered"><li><p>This should be false by default.</p></li><li><p>HTTP PATCH request should resolve to UPSERT* return default from code level from code level if the pushNotification pref is not found</p></li><li><p>Try UUID auto-gen for MySQL</p></li><li><p>Use Left JOIN on user-&gt; P.notifi.</p></li></ol><p><br></p><p><br><br></p>','\n',char(10)),'[]','2026-05-07T15:01:12.516077+00:00','2026-05-07T15:35:50.739435+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'427ea9568ec644eeb39e948fa92068f3','TWiR','<p></p><ul class="note_list_unordered"><li><p>[Lessons Learned Building High-Performance Rust Profiler](https://pawelurbanek.com/rust-performance-profiling)</p></li></ul><p></p><p></p><p>Founder AND hiring keyword search on linked in </p>','[]','2026-05-13T21:03:58.590794+00:00','2026-05-13T21:32:36.546457+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'7c00122204894fb2adb9847b1ef53086','Entitlement service notes',replace('<p>Subject ID - user/provider ID</p><p>subject type = provider or client</p><p></p><p></p><p></p><p>A subject has a plan,</p><p>A plan has roles</p><p>Roles contain permissions</p><p></p><pre><code class="language-json">subject-&gt;user_plan-&gt;plan_roles-&gt;roles-&gt;permission</code></pre><p><br></p><h2 class="notes_heading">Mock value for plan_roles</h2><pre><code class="language-sql">INSERT into  `plan_roles` (created_at, plan_identifier, role_identifier)  values (now(), "78be1c8f-060c-4b88-9a50-5cb1e4e5aabf" , "78be1c8f-060c-4b88-9a50-5cb1e4e5aabf");</code></pre><p><br></p><pre><code class="language-json">{\n    "subject": {\n        "type": "provider",\n        "identifier": "a3f1c2d4-8e5b-4f7a-9c0d-1b2e3f4a5b6c"\n    },\n    "permissions": {\n        "provider:byov_video": "false",\n        "provider:calendar_months": 6,\n        "provider:commission_rate": 0.2,\n        "provider:commission_rate_own_client": 0.2,\n        "provider:custom_booking_link": "false",\n        "provider:custom_domain": "false",\n        "provider:custom_website_publish": "false",\n        "provider:directory_featured": "false",\n        "provider:directory_priority_search": "false",\n        "provider:google_calendar_sync": "false",\n        "provider:max_active_clients": 5,\n        "provider:own_clients_bulk_import": "false",\n        "provider:own_clients_import": "false",\n        "provider:payouts_cadence_days": 7,\n        "provider:private_subdomain": "false",\n        "provider:session_notes_advanced_templates": "false",\n        "provider:session_notes_ai": "false",\n        "provider:support_tier": "email_48h"\n    }\n}\n</code></pre><p></p><h2 class="notes_heading"> Plan -&gt; Role mapping. <br><br></h2><p>Provider_<em>pro -&gt; provider_</em>pro</p><p></p>','\n',char(10)),'[]','2026-05-14T13:01:15.744726+00:00','2026-05-18T16:54:15.897062+00:00',X'e4a9def41a4247609e8eb54c76d82a3d');
INSERT INTO notes VALUES(X'4630db6a398b4cb48cb337748b387758','Learning PHP',replace('<p>Since you already do backend (Rust/Go/JS), I’d avoid beginner “what is a variable” material and go straight into modern PHP.</p><h3 class="notes_heading" style="text-align: start;">Phase 1 — Learn modern PHP (2–3 days)</h3><p style="text-align: start;">Read the official docs and focus on <strong>PHP 8+</strong> features:</p><ul class="note_list_unordered"><li><p><a href="https://www.php.net/docs.php?utm_source=chatgpt.com">PHP Documentation</a></p></li><li><p><a href="https://www.php.net/manual/en/langref.php?utm_source=chatgpt.com">PHP Manual – Language Reference</a></p></li></ul><p style="text-align: start;">Learn only these first:</p><pre><code class="language-php">&lt;?php\n\ndeclare(strict_types=1);\n\nclass User {\n    public function __construct(\n        public string $name,\n        public int $age\n    ) {}\n}\n\nfunction greet(User $user): string {\n    return "Hi {$user-&gt;name}";\n}\n</code></pre><p style="text-align: start;">Focus on:</p><ul class="note_list_unordered"><li><p>Classes</p></li><li><p>Typed properties</p></li><li><p>Interfaces</p></li><li><p>Enums</p></li><li><p>Traits</p></li><li><p>Exceptions</p></li><li><p>Namespaces</p></li><li><p>Attributes</p></li><li><p>Match expressions</p></li></ul><hr><h3 class="notes_heading" style="text-align: start;">Phase 2 — Composer + ecosystem (1 day)</h3><p style="text-align: start;">Composer = Cargo/NPM equivalent.</p><p style="text-align: start;">Install and learn:</p><pre><code class="language-bash">composer init\ncomposer require monolog/monolog\n</code></pre><p style="text-align: start;">Resource:</p><ul class="note_list_unordered"><li><p><a href="https://getcomposer.org/doc/?utm_source=chatgpt.com">Composer Docs</a></p></li></ul><p style="text-align: start;">Learn:</p><ul class="note_list_unordered"><li><p><code>composer.json</code></p></li><li><p>autoloading</p></li><li><p>PSR-4</p></li><li><p>dependency injection basics</p></li></ul><hr><h3 class="notes_heading" style="text-align: start;">Phase 3 — Build APIs immediately</h3><p style="text-align: start;">Skip raw PHP sites.</p><p style="text-align: start;">Use Laravel.</p><p style="text-align: start;">Resources:</p><ul class="note_list_unordered"><li><p><a href="https://laravel.com/docs?utm_source=chatgpt.com">Laravel Documentation</a></p></li><li><p><a href="https://bootcamp.laravel.com/?utm_source=chatgpt.com">Laravel Bootcamp</a></p></li><li><p><a href="https://laracasts.com/?utm_source=chatgpt.com">Laracasts</a></p></li></ul><p style="text-align: start;">Build:</p><pre><code>Auth API\nUsers\nPosts\nRedis cache\nQueue workers\nDocker\nPostgres\nJWT\n</code></pre><hr><h3 class="notes_heading" style="text-align: start;">Phase 4 — Architecture</h3><p style="text-align: start;">Learn:</p><ul class="note_list_unordered"><li><p>PSR standards</p></li><li><p>Service container</p></li><li><p>Middleware</p></li><li><p>Queues</p></li><li><p>Events</p></li><li><p>Repositories</p></li><li><p>Testing (Pest / PHPUnit)</p></li></ul><p style="text-align: start;">Read:</p><ul class="note_list_unordered"><li><p><a href="https://www.php-fig.org/psr/?utm_source=chatgpt.com">PHP-FIG PSRs</a></p></li></ul><hr><p style="text-align: start;">Suggested project for <em>you</em> specifically:</p><p style="text-align: start;"><strong>Rust experience → build a high-throughput API</strong></p><pre><code>Rust service (worker)\n      ↓\nRabbitMQ / Redis\n      ↓\nLaravel API\n      ↓\nPostgres\n</code></pre><p style="text-align: start;">You’ll see where PHP fits versus Rust infra work.</p>','\n',char(10)),'[]','2026-05-17T11:39:33.323812+00:00','2026-05-17T11:39:33.323813+00:00',X'ed42af204199419299e0965e2263d49e');
INSERT INTO notes VALUES(X'f4db303652a94b9abd7f7a8ba14cfca7','Features','<p></p><p></p><h2 class="notes_heading">App init —&nbsp;</h2><ol class="note_list_ordered"><li><p><s>create a new workspace table {id, first name, last name, email}</s></p></li><li><p><s>delete ollama codes</s></p></li><li><p><s>fix mysql migrations</s></p></li><li><p><s>remove email from the user_preference table</s></p></li><li><p>set security questions</p></li><li><p>Add an embedded page that asks for the password and email. This is used to generate cryptographic keys</p></li><li><p><s>Rename user-preference to workspace preference</s></p></li><li><p><s>Remove email from workspace preference</s></p></li><li><p>Add app_config that stores the master email and preferred auth method (enum — password or security question}</p></li><li><p>Add security questions table</p></li><li><p>link the security questions table to user pref</p></li><li><p>Create a requestAuth modal for sensitive actions</p></li><li><p>Restore the email to a unique constraint</p></li><li><p>Implement secure storage for the endpoint,</p></li></ol><p></p>','[]','2026-05-18T17:58:58.866487+00:00','2026-05-27T18:36:20.486162+00:00',X'8acc2c420fda43ae8636c9f39067e51d');
INSERT INTO notes VALUES(X'26c78cad81d44a2cb40f492e00ea8485','CV Drafts — Damilola. 857465','<p></p><h2 class="notes_heading">AI Prompts for Job Application</h2><ul class="note_list_unordered"><li><p><strong>Explode</strong> —&nbsp;expand the point</p></li><li><p><strong>Reimagine</strong> — recreate, paraphrase</p></li><li><p><strong>Tighten</strong>, remove excess, and leave major points</p></li><li><p>Find a fit —&nbsp;find the connection btw what I have and the job description </p></li><li><p>Roast – be brutally </p></li><li><p>suggest improvements <br></p></li></ul><p>Create a cover letter for the JOb description </p><p></p><p></p>','[]','2026-05-20T13:17:22.949037+00:00','2026-05-20T14:22:45.675962+00:00',X'ed42af204199419299e0965e2263d49e');
INSERT INTO notes VALUES(X'8d89177a14084df58bcce54df0d2517f','Csystem',replace('<p>It <em>feels</em> hard at first because C exposes a lot of things other languages hide.</p><p style="text-align: start;">You’re not just learning syntax; you’re learning how computers think:</p><ul class="note_list_unordered"><li><p>Variables → memory</p></li><li><p>Arrays → contiguous memory blocks</p></li><li><p>Pointers → addresses</p></li><li><p><code>malloc/free</code> → manual memory management</p></li><li><p><code>struct</code> → data layout</p></li><li><p>Files → system calls</p></li><li><p>Processes → OS concepts</p></li><li><p>Undefined behavior → “the machine will do what you asked, not what you meant” 😭</p></li></ul><p style="text-align: start;">Coming from Rust, OCaml, Kotlin, Vue, etc., C can feel like someone removed all the safety rails.</p><p style="text-align: start;">Example:</p><pre><code class="language-c">int arr[3] = {1,2,3};\012printf("%d\n", arr[10]); // compiles 💀\012</code></pre><p style="text-align: start;">Rust:</p><pre><code class="language-rust">let arr = [1,2,3];\012println!("{}", arr[10]); // nope\012</code></pre><p style="text-align: start;">But the upside is huge, especially for what you were asking earlier (systems path):</p><p style="text-align: start;"><strong>C → CS:APP → OS/Linux → networking → compilers → Rust internals</strong> is a very strong progression.</p><p style="text-align: start;">My suggestion for learning C without getting overwhelmed:</p><ol class="note_list_ordered"><li><p>Learn syntax + control flow</p></li><li><p>Arrays, strings, functions</p></li><li><p>Pointers (spend time here)</p></li><li><p>Memory (<code>malloc</code>, <code>free</code>)</p></li><li><p>Structs + files</p></li><li><p>Build tiny projects:</p><ul class="note_list_unordered"><li><p>mini grep</p></li><li><p>cat clone</p></li><li><p>wc clone</p></li><li><p>HTTP server</p></li><li><p>shell</p></li></ul></li><li><p>Read <strong>K&amp;R</strong> + <strong>CS:APP</strong></p></li></ol><p style="text-align: start;">The hard part is usually <strong>pointers + memory</strong>, not the whole language. Once that clicks, C becomes way less scary.</p>','\012',char(10)),'[]','2026-05-23T10:15:42.112438+00:00','2026-05-23T10:15:42.112438+00:00',X'ed42af204199419299e0965e2263d49e');
